import React from 'react';
import { Box, Text } from '@ggui-ai/design/primitives';
import { ElementCellProps } from '/virtual/types';

export const ElementCell: React.FC<ElementCellProps> = ({ element, isSelected, onClick }) => {
  const getCategoryColor = (category: string) => {
    switch (category) {
      case 'Noble Gas': return 'var(--ggui-color-primary-100)';
      case 'Halogen': return 'var(--ggui-color-info-100)';
      case 'Alkali Metal': return 'var(--ggui-color-success-100)';
      case 'Alkaline Earth Metal': return 'var(--ggui-color-warning-100)';
      default: return 'var(--ggui-color-surfaceVariant)';
    }
  };

  return (
    <div
      onClick={onClick}
      onKeyDown={(e: React.KeyboardEvent) => e.key === 'Enter' && onClick()}
      tabIndex={0}
      role="button"
      aria-label={`${element.name} (${element.symbol})`}
      style={{
        gridRow: element.row,
        gridColumn: element.col,
      }}
    >
      <Box
        background={getCategoryColor(element.category)}
        borderRadius="var(--ggui-shape-radius-md)"
        style={{
          padding: 'var(--ggui-spacing-3)',
          cursor: 'pointer',
          border: isSelected ? '2px solid var(--ggui-color-primary-500)' : '2px solid transparent',
          transition: 'all 200ms ease-in-out',
          display: 'flex',
          flexDirection: 'column',
          justifyContent: 'space-between',
          minWidth: '80px',
          minHeight: '80px',
        }}
      >
        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{element.atomicNumber}</Text>
        <Text variant="bodyLarge" weight="bold" align="center">{element.symbol}</Text>
      </Box>
    </div>
  );
};


