  const map: Record<string, string> = {
    'Alkali Metal': 'var(--ggui-color-primary-500)',
    'Alkaline Earth Metal': 'var(--ggui-color-secondary-500)',
    'Transition Metal': 'var(--ggui-color-info-500)',
