import { ProfileData } from '/virtual/types';

export const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

export const TOTAL_STEPS = 3;

export const STEP_LABELS: Record<number, string> = {
  1: 'Profile Setup',
  2: 'Preferences',
  3: 'Review',
};

export const DEFAULT_PROFILE_DATA: ProfileData = {
  name: '',
  email: '',
  avatar: '',
  role: '',
  emailNotifications: false,
  theme: 'light',
};

export const WIZARD_STEPS = [1, 2, 3];

export const VALIDATORS: Record<number, (data: ProfileData) => boolean> = {
  1: (data: ProfileData) => {
    return !!(
      data.name.trim().length > 0 &&
      EMAIL_REGEX.test(data.email) &&
      data.avatar !== '' &&
      data.role !== ''
    );
  },
  2: (data: ProfileData) => {
    // Preferences step is always valid if reached
    return true;
  },
  3: (data: ProfileData) => {
    // Review step is final, disable "next" as it's a finish step
    return false;
  },
};

