import type { OnboardingWizardProps, ProfileData, HookReturn } from '/virtual/types';
import * as constants from '/virtual/constants';
// hooks.ts — state, handlers, data transformations
import { useState, useMemo, useCallback } from 'react';

export function useOnboardingWizard(props: OnboardingWizardProps): HookReturn {
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState<ProfileData>(() => ({
    name: "",
    email: "",
    avatar: props.avatarOptions[0] || "",
    role: props.roleOptions[0] || "",
    emailNotifications: false,
    theme: 'light',
    ...props.initialProfile,
  }));

  const isNextDisabled = useMemo(() => {
    if (currentStep === 1) {
      const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
      return !formData.name || !formData.email || !emailRegex.test(formData.email);
    }
    return false;
  }, [currentStep, formData.name, formData.email]);

  const handleNext = useCallback(() => {
    if (currentStep < 3) {
      setCurrentStep((prev) => prev + 1);
    } else {
      props.onComplete(formData);
    }
  }, [currentStep, formData, props]);

  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep((prev) => prev - 1);
    }
  }, [currentStep]);

  const updateField = useCallback(<K extends keyof ProfileData>(key: K, value: ProfileData[K]) => {
    setFormData((prev) => ({ ...prev, [key]: value }));
  }, []);

  return {
    currentStep,
    formData,
    isNextDisabled,
    handleNext,
    handleBack,
    updateField,
  };
}

export function useComponent() {
  // Placeholder for component hook if required by architecture
  return {};
}

