            <Box>
              {currentStep === 1 && <Text>Step 1: Profile Information</Text>}
              {currentStep === 2 && <Text>Step 2: Preferences</Text>}
              {currentStep === 3 && <Text>Step 3: Summary</Text>}
            </Box>

            <Divider />

            <Row justify="between">
              <Button 
                variant="ghost" 
                onClick={handleBack} 
                disabled={currentStep === 1}
              >
                Back
              </Button>
              <Button 
                variant="primary" 
                onClick={handleNext} 
                disabled={isNextDisabled}
              >
                {currentStep === 3 ? 'Finish' : 'Next'}
              </Button>
            </Row>
          </Stack>
        </Box>
      </Stack>
    </Container>
  );
}


