import type { Props, HookReturn } from '/virtual/types';
import React from 'react';
import { Container, Card, Stack, Box, Heading, Button, Progress } from '@ggui-ai/design/primitives';
// Assume steps are available at these paths

export function MainView(props: Props & HookReturn) {
  const { currentStep, formData, isNextDisabled, handleNext, handleBack, updateField } = props;

  const renderStep = () => {
    switch (currentStep) {
      case 1: return <ProfileSetupStep data={formData} updateField={updateField} />;
      case 2: return <PreferencesStep data={formData} updateField={updateField} />;
      case 3: return <SummaryView data={formData} />;
      default: return null;
    }
  };

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-4)">
      <Card padding="var(--ggui-spacing-6)" shadow="md">
        <Stack gap="var(--ggui-spacing-4)">
          <Heading level={3}>Step {currentStep} of 3</Heading>
          <Progress value={currentStep} max={3} />
          <Box paddingY="var(--ggui-spacing-4)">{renderStep()}</Box>
          <Stack direction="horizontal" justify="between">
            <Button variant="secondary" onClick={handleBack} disabled={currentStep === 1}>Back</Button>
            <Button variant="primary" onClick={handleNext} disabled={isNextDisabled}>
              {currentStep === 3 ? 'Complete Setup' : 'Next'}
            </Button>
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}


